#include <bits/stdc++.h>

using namespace std;

typedef long long ll;

const int MAXN = 3e3 + 5;

const int INF = 0x7f7f7f7f;

const ll p = 998244353;

#define DEBUG(x) cout << x << '\n'



int n, s, t, f[MAXN];

ll f_pow(ll a, ll b){

    ll res = 1;

    for(; b; b >>= 1, a = a * a % p)

        if(b & 1) res = res * a % p;

    return res;

}

int main(){

#ifdef Irene

    freopen("in.txt", "r", stdin);

#endif // Irene

    ios::sync_with_stdio(false);



    cin >> n >> s;

    f[0] = f_pow(2, n);

    ll inv2 = f_pow(2, p - 2);

    for(int i = 1; i <= n; i++){

        cin >> t;

        for(int j = s - t; j >= 0; j--)

            f[j+t] = (f[j+t] + f[j] * inv2) % p;

    }

    cout << f[s];

}

